use std::collections::BinaryHeap;
use std::cmp::Reverse;

fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let n = nums.len();

    // 1. Precompute closest(x) for all x
    let mut closest = vec![0; n];
    for x in 0..n {
        let mut min_diff = i64::MAX;
        let mut best_y = -1;

        // Check adjacent indices y
        let neighbors = if x > 0 { vec![x - 1] } else { vec![] };
        let neighbors = neighbors.iter().chain(if x < n - 1 { vec![x + 1].into_iter() } else { vec![] }).cloned().collect::<Vec<usize>>();

        if neighbors.is_empty() {
            closest[x] = x; 
            continue;
        }

        for &y in &neighbors {
            let diff = (nums[x] - nums[y]).abs();
            if diff < min_diff {
                min_diff = diff;
                best_y = y as i32;
            } else if diff == min_diff {
                // If differences are equal, choose the smaller index y
                if y as i32 < best_y {
                    best_y = y as i32;
                }
            }
        }
        closest[x] = best_y as usize;
    }

    let mut results = Vec::new();

    // 2. Process each query using Dijkstra's Algorithm
    for query in queries {
        let l_query = query[0] as usize;
        let r_query = query[1] as usize;
        let start_node = l_query;
        let end_node = r_query;

        let mut dist: Vec<i64> = vec![i64::MAX; n];
        dist[start_node] = 0;

        // Priority Queue: stores (cost, node). Use Reverse for min-heap.
        let mut pq: BinaryHeap<Reverse<(i64, usize)>> = BinaryHeap::new();
        pq.push(Reverse((0, start_node)));

        while let Some(Reverse((d, u))) = pq.pop() {
            if d > dist[u] {
                continue;
            }
            if u == end_node {
                break;
            }

            // Transition 1: Type B move to closest(u), cost 1
            let v_b = closest[u];
            let new_dist_b = d + 1;
            if new_dist_b < dist[v_b] {
                dist[v_b] = new_dist_b;
                pq.push(Reverse((new_dist_b, v_b)));
            }

            // Transition 2: Type A move to ANY v, cost |nums[u] - nums[v]|
            for v in 0..n {
                if u == v { continue; }

                let cost_a = (nums[u] - nums[v]).abs();
                let new_dist_a = d + cost_a;

                if new_dist_a < dist[v] {
                    dist[v] = new_dist_a;
                    pq.push(Reverse((new_dist_a, v)));
                }
            }
        }
        results.push(dist[end_node]);
    }

    results
}
