fn solve(nums: Vec<i64>, queries: Vec<Vec<i64>>) -> Vec<i64> {
    let n = nums.len();

    // 1. Precompute closest(x) for all x
    let mut closest = vec![0; n];
    for x in 0..n {
        let mut min_diff = i64::MAX;
        let mut best_y = -1;

        // Neighbors are x-1 and x+1
        let mut neighbors = Vec::new();
        if x > 0 {
            neighbors.push(x - 1);
        }
        if x < n - 1 {
            neighbors.push(x + 1);
        }

        if neighbors.is_empty() {
            closest[x] = x as i32; 
            continue;
        }

        for &y in neighbors.iter() {
            let diff = (nums[x] - nums[y]).abs();
            if diff < min_diff {
                min_diff = diff;
                best_y = y as i32;
            } else if diff == min_diff {
                // If differences are equal, choose the smaller index y
                let current_best_y = best_y as usize;
                let y_usize = y;
                if y_usize < current_best_y {
                    best_y = y as i32;
                }
            }
        }
        closest[x] = best_y;
    }

    let mut results = Vec::new();

    // 2. Process each query using Dijkstra's Algorithm
    for query in queries {
        let l_query = query[0] as usize;
        let r_query = query[1] as usize;

        // dist[i] stores the minimum cost to reach index i from the start node
        let mut dist: Vec<i64> = vec![i64::MAX; n];
        let mut heap = BinaryHeap::new();

        dist[l_query] = 0;
        // Use Reverse for min-heap behavior
        heap.push(Reverse((0i64, l_query)));

        while let Some(Reverse((d, u))) = heap.pop() {
            if d > dist[u] {
                continue;
            }
            if u == r_query {
                break;
            }

            // Transition 1: Move to closest(u), cost 1
            let v_b = closest[u] as usize;
            let new_dist_b = d + 1;
            if new_dist_b < dist[v_b] {
                dist[v_b] = new_dist_b;
                heap.push(Reverse((new_dist_b, v_b)));
            }

            // Transition 2: Move to ANY v, cost |nums[u] - nums[v]|
            for v in 0..n {
                if u == v {
                    continue;
                }

                let cost_a = (nums[u] - nums[v]).abs();
                let new_dist_a = d + cost_a;

                if new_dist_a < dist[v] {
                    dist[v] = new_dist_a;
                    heap.push(Reverse((new_dist_a, v)));
                }
            }
        }

        results.push(dist[r_query]);
    }

    results
}
